mapper.select:
WITH filtered_log AS ( SELECT l.id, l.user_id, l.username, l.success, l.created_at FROM sys_login_log l LEFT JOIN sys_user u ON u.id = l.user_id AND u.deleted = 0
l.deleted = 0
AND l.username = #{username}
AND l.success = #{success}
AND l.created_at >= #{startTime}
AND l.created_at <= #{endTime}
) SELECT CAST(DATE_TRUNC('day', created_at) AS date) AS stat_date, username, COUNT(*) AS total_count, SUM(CASE WHEN success THEN 1 ELSE 0 END) AS success_count, SUM(CASE WHEN success THEN 0 ELSE 1 END) AS failure_count, MIN(CAST(created_at AS date)) AS first_login_date, MAX(CAST(created_at AS date)) AS last_login_date FROM filtered_log GROUP BY CAST(DATE_TRUNC('day', created_at) AS date), username ORDER BY stat_date DESC, total_count DESC, username ASC
